1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: {
12	    cause: string;
13	    damages: { itemType: string; amount: number }[];
14	  };
15	};
16	type Step = QuoteStep | ClaimStep;
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	
19	const FIRST_INSURANCE_MULTIPLIER = 1.1;
20	const POST_FIRST_CONTRACT_MULTIPLIER = 0.85;
21	const CURSED_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
23	const LOYALTY_MULTIPLIER = 0.8;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const ADMIN_FEE = 5;
26	
27	// Three alike pieces of a "building-block" item (rune, moonstone, â€¦) pool
28	// to a single unit priced at this fixed tier, irrespective of the per-piece
29	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
30	// is conceptually a separate pricing rule from the per-item ladder.
31	const BUILDING_BLOCK_PRICE = 60;
32	
33	const BASE_PRICE: Record<string, number> = {
34	  sword: 100,
35	  staff: 80,
36	  amulet: 60,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const POOLED_TYPES = new Set(["rune", "moonstone"]);
43	
44	function itemModifierMultiplier(item: Item): number {
45	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
46	  const highEnchantment =
47	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
48	  return cursed * highEnchantment;
49	}
50	
51	// MHPCO always rounds the euro value of a discounted/loaded price upward
52	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
53	// values that are mathematically integer (e.g. 100 Ă— 1.10 = 110) don't get
54	// bumped up a euro by a 110.00000000000001 representation.
55	function ceilInMhpcoFavor(value: number): number {
56	  return Math.ceil(Number(value.toFixed(10)));
57	}
58	
59	// Sum of per-item base prices (with item-attribute multipliers applied)
60	// for a single quote. Building-block items (rune today, moonstone in cycle
61	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
62	// back to the per-piece BASE_PRICE.
63	function quoteItemsSubtotal(items: Item[]): number {
64	  let subtotal = 0;
65	  const pooledCounts = new Map<string, number>();
66	  for (const item of items) {
67	    if (POOLED_TYPES.has(item.type)) {
68	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
69	    } else {
70	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
71	    }
72	  }
73	  for (const [type, count] of pooledCounts) {
74	    const buildingBlocks = Math.floor(count / 3);
75	    const loose = count % 3;
76	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
77	  }
78	  return subtotal;
79	}
80	
81	// Reimbursement percentage by item attribute (dragon material always wins
82	// today; enchantment 9 and other tiers will join here in later cycles).
83	function itemReimbursementFraction(item: Item | undefined): number {
84	  if (item?.material === "dragon") return 1;
85	  if ((item?.enchantment ?? 0) >= 8) return 0.5;
86	  return 0;
87	}
88	
89	const DEDUCTIBLE = 100;
90	
91	// Look up the insured item on the originating quote (referenced by
92	// `claimStep.policy` as an index into the step list), compute the
93	// reimbursement for the incident, subtract the flat deductible, and floor
94	// the payout at zero.
95	function claimPayout(claimStep: ClaimStep, allSteps: Step[]): { payout: number } {
96	  const policyStep = allSteps[claimStep.policy] as QuoteStep;
97	  const damage = claimStep.incident.damages[0];
98	  const item = policyStep.items.find((i) => i.type === damage.itemType);
99	  const reimbursement = damage.amount * itemReimbursementFraction(item);
100	  return { payout: Math.max(0, reimbursement - DEDUCTIBLE) };
101	}
102	
103	export function runScenario(scenario: unknown): unknown {
104	  const { customer, steps } = scenario as Scenario;
105	  const loyaltyMultiplier =
106	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
107	  const results = steps.map((step, quoteIndex) => {
108	    if (step.op === "claim") return claimPayout(step, steps);
109	    const itemsSubtotal = quoteItemsSubtotal(step.items);
110	    const contractMultiplier =
111	      quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : POST_FIRST_CONTRACT_MULTIPLIER;
112	    const premium =
113	      ceilInMhpcoFavor(itemsSubtotal * loyaltyMultiplier * contractMultiplier) +
114	      ADMIN_FEE;
115	    return { premium };
116	  });
117	  return { results };
118	}
